3939   // so that scalable vectorization is slightly favorable over fixed-width
3940   // vectorization.
3941   bool PreferScalable = !TTI.preferFixedOverScalableIfEqualCost(IsEpilogue) &&
3942                         A.Width.isScalable() && !B.Width.isScalable();
